// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PurchaseReceiptAdjustment) predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PurchaseReceiptAdjustment) predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PurchaseReceiptAdjustment) predicate.PurchaseReceiptAdjustment {
	return predicate.PurchaseReceiptAdjustment(sql.NotPredicates(p))
}
